INSERT INTO objection_cases (id, category, category_label, objection_text, response_text, tags, content_hash, is_seed, created_at) VALUES
  ('obj_001', 'price', 'Ценовые возражения', 'У вас слишком дорого', 'Я понимаю ваше желание сэкономить. Давайте посмотрим не на цену за канистру, а на совокупную стоимость владения. Наше масло содержит пакет присадок [название], который снижает трение и экономит до 5% топлива, а также позволяет увеличить интервал замены масла вдвое по сравнению со стандартным продуктом. Экономия на ремонте и простоях перекроет разницу в цене.', '{"слишком","дорого","понимаю","ваше","желание","сэкономить","давайте","посмотрим"}', '60603814df65b4a6', true, NOW()),
  ('obj_002', 'price', 'Ценовые возражения', 'Конкурент предложил дешевле', 'Спасибо за информацию. Чтобы сравнение было честным, давайте проверим спецификации: у нас допуск [OEM-допуск] и класс вязкости SAE [класс]. Соответствует ли продукт конкурента этим требованиям для вашей техники? Часто более низкая цена означает отсутствие критически важных присадок, что ведет к износу двигателя.', '{"конкурент","предложил","дешевле","спасибо","информацию","сравнение","честным","давайте"}', 'bc2e517d5692cfd8', true, NOW()),
  ('obj_003', 'price', 'Ценовые возражения', 'Дайте скидку 20%', 'Наша маржинальность не позволяет дать такую большую разовую скидку без потери качества продукта. Однако при переходе на годовой объем поставок от [объем] тонн мы готовы зафиксировать специальную цену или обсудить ретро-бонус по итогам года.', '{"дайте","скидку","маржинальность","позволяет","дать","такую","большую","разовую"}', 'dba57ffe17652718', true, NOW()),
  ('obj_004', 'price', 'Ценовые возражения', 'Почему такая разница с прошлым годом? (Цены выросли)', 'Это связано с волатильностью цен на базовые масла III группы и импортные пакеты присадок на мировом рынке. Мы стараемся удерживать цены максимально долго, но вынуждены корректировать их вслед за сырьем. Для защиты вашего бюджета предлагаем заключить долгосрочный контракт с фиксацией цены.', '{"почему","такая","разница","прошлым","годом","цены","выросли","связано"}', '06d6aa2c5be8aeff', true, NOW()),
  ('obj_005', 'price', 'Ценовые возражения', 'В вашем коммерческом предложении ошибка: цена завышена', 'Давайте перепроверим вместе. Возможно, я ошибочно применил коэффициент логистики для вашего региона или учел НДС. Продублируйте мне артикулы позиций и объем, я сделаю перерасчет в течение 15 минут.', '{"вашем","коммерческом","предложении","ошибка","цена","завышена","давайте","перепроверим"}', '66d736a5d6dd6be4', true, NOW()),
  ('obj_006', 'price', 'Ценовые возражения', 'Мы работаем только по тендеру / Бюджет уже утвержден', 'Понимаю. Я могу подготовить техническое обоснование для закупочного комитета, почему наш продукт оптимален именно для ваших условий эксплуатации. Это поможет нам попасть в следующий цикл закупок или стать резервным поставщиком.', '{"работаем","тендеру","бюджет","утвержден","понимаю","могу","подготовить","техническое"}', '07d0bd2f1e7725c9', true, NOW()),
  ('obj_007', 'price', 'Ценовые возражения', 'Нам нужен товар со склада прямо сейчас за полцены', 'К сожалению, распродажа остатков ниже себестоимости невозможна — это нарушает нашу финансовую политику. Но я вижу, что вам нужна срочная поставка. Товар есть на нашем региональном складе, доставка будет завтра. Цена будет стандартной, как в прайс-листе.', '{"нужен","товар","склада","прямо","полцены","сожалению","распродажа","остатков"}', '70b3e4ea0da2b2bf', true, NOW()),
  ('obj_008', 'price', 'Ценовые возражения', 'Ваша цена неконкурентоспособна на рынке', 'Мы позиционируем себя в сегменте', '{"цена","неконкурентоспособна","рынке","позиционируем","сегменте"}', '61db093dc33cf829', true, NOW()),
  ('obj_009', 'price', 'Ценовые возражения', 'Зачем платить больше, если масло выполняет ту же функцию?', 'Функция одна — смазывать. А вот *как* она выполняется — вопрос технологии. Наше масло защищает от LSPI (преждевременного воспламенения смеси), что критично для современных двигателей малого объема. Ремонт турбины стоит дороже всей экономии.', '{"платить","масло","выполняет","функцию","функция","одна","смазывать","выполняется"}', '5fae15b61f666a1f', true, NOW()),
  ('obj_010', 'price', 'Ценовые возражения', 'У нас нет бюджета на премиальные продукты', 'Тогда давайте подберем линейку из нашего стандартного ассортимента. Она имеет все необходимые допуски, но стоит дешевле за счет оптимизации пакета присадок под стандартные условия эксплуатации.', '{"бюджета","премиальные","продукты","давайте","подберем","линейку","нашего","стандартного"}', 'c19afb37303aa28c', true, NOW()),
  ('obj_011', 'price', 'Ценовые возражения', 'Вы предлагаете цену выше рыночной', 'Рыночная цена часто является ценой входа. Наша цена включает сервис: бесплатную доставку при заказе от [суммы], персонального менеджера и расширенную гарантию на двигатель при использовании нашей продукции.', '{"предлагаете","цену","выше","рыночной","рыночная","цена","часто","является"}', '3de07545b2d152af', true, NOW()),
  ('obj_012', 'price', 'Ценовые возражения', 'Включите доставку в стоимость товара без увеличения цены', 'Доставка уже заложена в логистический коэффициент. Если вы увеличите объем заказа до [объем], мы сможем предложить бесплатную доставку в черте города.', '{"включите","доставку","стоимость","товара","увеличения","цены","доставка","заложена"}', 'f7f9abd39a195804', true, NOW()),
  ('obj_013', 'price', 'Ценовые возражения', 'Мы покупаем у производителя напрямую, зачем нам посредник?', 'Мы являемся официальным дистрибьютором, что дает вам заводскую гарантию, но при этом обеспечивает наличие полного ассортимента на складе здесь и сейчас. Плюс мы оказываем техническую поддержку и берем на себя документооборот.', '{"покупаем","производителя","напрямую","посредник","являемся","официальным","дистрибьютором","дает"}', 'eaa3110a3c2f7ef9', true, NOW()),
  ('obj_014', 'price', 'Ценовые возражения', 'Цена нестабильна, мы не можем так планировать закупки', 'Именно поэтому мы предлагаем услугу хеджирования цен. Заключаем договор на полгода-год с фиксацией стоимости, защищая ваш бюджет от скачков котировок на бирже.', '{"цена","нестабильна","можем","планировать","закупки","именно","поэтому","предлагаем"}', 'd32b667e36c83e22', true, NOW()),
  ('obj_015', 'price', 'Ценовые возражения', 'Ваш продукт не стоит своих денег', 'Позвольте продемонстрировать расчет окупаемости. Замена масла происходит реже, экономия топлива составляет X%, снижение износа деталей подтверждено протоколами испытаний. Вот цифры.', '{"продукт","стоит","своих","денег","позвольте","продемонстрировать","расчет","окупаемости"}', 'fb60a7d3a3072879', true, NOW()),
  ('obj_016', 'price', 'Ценовые возражения', 'Мы требуем ретро-бонус за объем закупок прошлого года', 'Ретро-бонусы начисляются автоматически по итогам квартала и отражаются в счете-фактуре следующего периода. Проверю вашу историю платежей и пришлю отчет.', '{"требуем","ретро-бонус","объем","закупок","прошлого","года","ретро-бонусы","начисляются"}', '89913df59187cea9', true, NOW()),
  ('obj_017', 'price', 'Ценовые возражения', 'Оплата наличными/по факту поставки — это ваше условие?', 'Для новых клиентов возможна оплата по факту разгрузки после первой пробной партии. Далее мы переходим на безналичный расчет с отсрочкой платежа 14 дней.', '{"оплата","наличными","факту","поставки","ваше","условие","новых","клиентов"}', 'ca7d43af5b843996', true, NOW()),
  ('obj_018', 'price', 'Ценовые возражения', 'Вы не даете отсрочку платежа', 'Отсрочка предоставляется после трех успешных отгрузок и проверки финансовой дисциплины компании. Сейчас мы готовы начать работу по предоплате, чтобы выстроить доверие.', '{"даете","отсрочку","платежа","отсрочка","предоставляется","трех","успешных","отгрузок"}', 'bcde7a9f78a63107', true, NOW()),
  ('obj_019', 'price', 'Ценовые возражения', 'Минимальная партия для заказа слишком велика', 'Стандартная минимальная партия обусловлена рентабельностью доставки. Но мы можем объединить ваш заказ с другим клиентом в вашем районе или предложить поставку в еврокубах (IBC-контейнерах), которые легче разгружать.', '{"минимальная","партия","заказа","слишком","велика","стандартная","обусловлена","рентабельностью"}', '450813631c90b89b', true, NOW()),
  ('obj_020', 'price', 'Ценовые возражения', 'Пробная партия слишком мала и невыгодна по цене', 'Цена пробной партии действительно выше из-за логистики. Предлагаю считать её инвестицией в будущее партнерство. При заказе основной партии эта разница будет компенсирована скидкой.', '{"пробная","партия","слишком","мала","невыгодна","цене","цена","пробной"}', 'c6e30dc9bf18c6b2', true, NOW()),
  ('obj_021', 'quality', 'Качество и Технические Характеристики', 'Ваше масло темнеет через неделю — это брак?', 'Нет, это признак того, что работают мощные моющие присадки. Они растворяют нагар и шламы, накопленные в системе, выводя грязь в фильтр. Масло выполняет свою работу по очистке двигателя.', '{"ваше","масло","темнеет","неделю","брак","признак","работают","мощные"}', 'c562dcbc9ede0ebb', true, NOW()),
  ('obj_022', 'quality', 'Качество и Технические Характеристики', 'Масло быстро расходуется / угорает', 'Повышенный расход чаще всего связан с износом цилиндро-поршневой группы или направляющих клапанов. Рекомендую провести диагностику состояния узлов. Переход на наше масло с повышенной вязкостью может решить проблему утечек.', '{"масло","быстро","расходуется","угорает","повышенный","расход","чаще","связан"}', '9e0bc44835d9ac81', true, NOW()),
  ('obj_023', 'quality', 'Качество и Технические Характеристики', 'Не подходит по щелочному числу (TBN) / кислотному числу (TAN)', 'У нас есть специализированная линейка масел для тяжелых условий с повышенным TBN. Оно рассчитано на топливо с высоким содержанием серы. Подскажите параметры вашего топлива, и я подберу точный продукт.', '{"подходит","щелочному","числу","tbn","кислотному","tan","специализированная","линейка"}', 'd4abc3dda538c68b', true, NOW()),
  ('obj_024', 'quality', 'Качество и Технические Характеристики', 'Слишком жидкое / густое при рабочей температуре', 'Возможно, используется неправильный класс вязкости. Проверьте рекомендации OEM для текущей температуры окружающей среды. Мы можем подобрать оптимальный вариант SAE.', '{"слишком","жидкое","густое","рабочей","температуре","возможно","используется","неправильный"}', '58264bc13e367801', true, NOW()),
  ('obj_025', 'quality', 'Качество и Технические Характеристики', 'Нет одобрения нашего завода-изготовителя техники (OEM)', 'Продукт соответствует допускам [список допусков], которые эквивалентны требованиям вашего OEM. Готов предоставить официальное письмо о соответствии от нашего технического отдела.', '{"одобрения","нашего","завода-изготовителя","техники","oem","продукт","соответствует","допускам"}', '9711f744e8d412a0', true, NOW()),
  ('obj_026', 'quality', 'Качество и Технические Характеристики', 'Где ваши сертификаты/допуски OEM?', 'Вот паспорта безопасности (MSDS) и технические описания (TDS). Копии сертификатов соответствия я отправлю вам на почту сразу после нашего разговора.', '{"сертификаты","допуски","oem","паспорта","безопасности","msds","технические","описания"}', '637e9579a413b6aa', true, NOW()),
  ('obj_027', 'quality', 'Качество и Технические Характеристики', 'Ваши показатели вязкости отличаются от заявленных', 'Вязкость измеряется строго при 40°C и 100°C согласно методике ASTM D445. Разница в доли сантистокса допустима погрешностью лаборатории. Наш продукт проходит двойной контроль качества.', '{"показатели","вязкости","отличаются","заявленных","вязкость","измеряется","строго","согласно"}', '1499fdef9777ad80', true, NOW()),
  ('obj_028', 'quality', 'Качество и Технические Характеристики', 'Срок годности масла истекает раньше, чем мы его используем', 'Срок хранения закрытой тары — 5 лет. Как только бочка вскрывается, срок сокращается до 1 года из-за контакта с воздухом и влагой. Предлагаем перейти на фасовку меньшего объема.', '{"срок","годности","масла","истекает","раньше","используем","хранения","закрытой"}', '484bcbe500e1018b', true, NOW()),
  ('obj_029', 'quality', 'Качество и Технические Характеристики', 'После замены масла начались течи сальников', 'Наше современное масло обладает высокой текучестью и чистящими свойствами. Оно вымывает отложения, которые ранее служили «уплотнителем', '{"замены","масла","начались","течи","сальников","современное","масло","обладает"}', 'c595bb9874b8b091', true, NOW()),
  ('obj_030', 'quality', 'Качество и Технические Характеристики', 'Образовался нагар или лаковые отложения', 'Это следствие использования некачественного базового масла или перегрева. Наш продукт содержит беззольный пакет присадок, предотвращающий образование лака. Рекомендация: промыть систему нашим промывочным составом перед заменой.', '{"образовался","нагар","лаковые","отложения","следствие","использования","некачественного","базового"}', '17b6560e62293d13', true, NOW()),
  ('obj_031', 'quality', 'Качество и Технические Характеристики', 'Повышенный износ деталей после использования вашего продукта', 'Это серьезное обвинение. Прошу сохранить пробы отработанного масла. Мы проведем независимую экспертизу в лаборатории. Пока результат не получен, рекомендую вернуться к регламенту обслуживания.', '{"повышенный","износ","деталей","использования","вашего","продукта","серьезное","обвинение"}', '407c1f036acf9d53', true, NOW()),
  ('obj_032', 'quality', 'Качество и Технические Характеристики', 'Масло вспенивается', 'Причина может быть в попадании воды в картер или переливе уровня. Также возможно использование неподходящего продукта с низким антипенным свойством. Какой продукт был залит?', '{"масло","вспенивается","причина","попадании","воды","картер","переливе","уровня"}', '833f947491f9eb6c', true, NOW()),
  ('obj_033', 'quality', 'Качество и Технические Характеристики', 'Расслоение продукта при хранении', 'Такое случается при глубоком замораживании базовых масел низкого качества. Наш продукт гомогенизирован и выдерживает циклы заморозки-разморозки. Перед использованием просто перемешайте содержимое бочки.', '{"расслоение","продукта","хранении","такое","случается","глубоком","замораживании","базовых"}', '7f1e9ce46d72580e', true, NOW()),
  ('obj_034', 'quality', 'Качество и Технические Характеристики', 'Несовместимость с уплотнительными материалами нашей техники', 'Наши эластомеры совместимы с современными синтетическими маслами. Проблема скорее в том, что старое уплотнение задубело. Масло лишь проявило дефект.', '{"несовместимость","уплотнительными","материалами","нашей","техники","наши","эластомеры","совместимы"}', '58e71c2464ea953d', true, NOW()),
  ('obj_035', 'quality', 'Качество и Технические Характеристики', 'Неприятный запах / цвет / консистенция', 'Цвет и запах зависят от типа базового масла и присадок. Главное — соответствие стандартам API/ACEA. Если консистенция неоднородна, возможен брак партии. Давайте возьмем пробу из этой бочки.', '{"неприятный","запах","цвет","консистенция","зависят","типа","базового","масла"}', '281b62c43ee2e8a9', true, NOW()),
  ('obj_036', 'quality', 'Качество и Технические Характеристики', 'Нет нужного класса вязкости (например, XW-XX)', 'Да, наша основная линейка ориентирована на массовый спрос. Но мы производим спецпродукты под заказ. Оставьте заявку, и технологи разработают формулу под ваши нужды.', '{"нужного","класса","вязкости","например","xw-xx","основная","линейка","ориентирована"}', 'c904976cf9fdd006', true, NOW()),
  ('obj_037', 'quality', 'Качество и Технические Характеристики', 'Продукт замерзает зимой / становится слишком текучим летом', 'Температура застывания нашего зимнего продукта -42°C. Летний сохраняет вязкость при +50°C. Вы уверены, что используете правильный класс вязкости SAE для сезона?', '{"продукт","замерзает","зимой","становится","слишком","текучим","летом","температура"}', '43d5b155887eaf6f', true, NOW()),
  ('obj_038', 'quality', 'Качество и Технические Характеристики', 'Высокий уровень сульфатной зольности (для сажевых фильтров DPF)', 'Вы правы, для систем с DPF нужно масло Low SAPS. У нас есть отдельная линейка [Название линейки] с пониженным содержанием сульфатной золы, фосфора и серы.', '{"высокий","уровень","сульфатной","зольности","сажевых","фильтров","dpf","правы"}', '7f9c870803fc4686', true, NOW()),
  ('obj_039', 'quality', 'Качество и Технические Характеристики', 'Низкая температура вспышки', 'Низкая температура вспышки говорит о наличии легких фракций или топлива в масле (разжижение). Если это свежий продукт, это повод проверить партию. Пришлите фото маркировки.', '{"низкая","температура","вспышки","говорит","наличии","легких","фракций","топлива"}', 'b5ca6fb633cd86bb', true, NOW()),
  ('obj_040', 'quality', 'Качество и Технические Характеристики', 'Высокая испаряемость (NOACK)', 'Высокий NOACK увеличивает расход масла на угар. В нашей синтетической линейке этот показатель менее 10%, что соответствует самым строгим европейским стандартам.', '{"высокая","испаряемость","noack","высокий","увеличивает","расход","масла","угар"}', '5fcd0f57e79649c4', true, NOW()),
  ('obj_041', 'logistics', 'Логистика и Сроки', 'Срок поставки слишком долгий', 'Стандартный срок — 7-10 дней. Чтобы ускорить процесс, предлагаю перевести вас на систему планирования запасов. Вы формируете прогноз, мы держим буферный запас на складе специально для вас.', '{"срок","поставки","слишком","долгий","стандартный","7-10","дней","ускорить"}', 'cfb235b43e555cfb', true, NOW()),
  ('obj_042', 'logistics', 'Логистика и Сроки', 'Доставка платная / дорогая', 'Логистика включена в стоимость. При достижении объема ежемесячных закупок [сумма] рублей доставка до вашего терминала становится бесплатной.', '{"доставка","платная","дорогая","логистика","включена","стоимость","достижении","объема"}', 'a364418037e9d1a7', true, NOW()),
  ('obj_043', 'logistics', 'Логистика и Сроки', 'Склад находится далеко от нас', 'У нас широкая сеть филиалов. Ближайший к вам склад находится в [Город]. Оттуда возможна быстрая доставка. Могу рассчитать стоимость?', '{"склад","находится","далеко","широкая","сеть","филиалов","ближайший","город"}', '2ad746fef36e6d8d', true, NOW()),
  ('obj_044', 'logistics', 'Логистика и Сроки', 'Нужен срочный заказ «вчера»', 'Понимаю ситуацию. Есть небольшой сток ходовых позиций на центральном складе. Что именно требуется? Можем отправить фурой сегодня вечером.', '{"нужен","срочный","заказ","вчера","понимаю","ситуацию","небольшой","сток"}', '5a7905d0f2ff7b08', true, NOW()),
  ('obj_045', 'logistics', 'Логистика и Сроки', 'У вас неудобные фасовки (бочки тяжелые)', 'Для удобства разгрузки вашим персоналом мы предлагаем поставку в еврокубах (IBC-контейнеры) или бочках меньшего объема. Также возможен монтаж насосного оборудования.', '{"неудобные","фасовки","бочки","тяжелые","удобства","разгрузки","вашим","персоналом"}', '570f0f71eaf2cdb4', true, NOW()),
  ('obj_046', 'logistics', 'Логистика и Сроки', 'Нужна тара другого цвета или маркировки', 'Маркировка наносится промышленным способом и стандартизирована. Изменение цвета пластика невозможно. Но мы можем наклеить ваши стикеры поверх штатной этикетки.', '{"нужна","тара","другого","цвета","маркировки","маркировка","наносится","промышленным"}', '28a87e88ef28e264', true, NOW()),
  ('obj_047', 'logistics', 'Логистика и Сроки', 'Сложно разгружать ваш транспорт', 'Водители оснащены гидробортами. Если этого недостаточно, рекомендуем использовать паллетообмотчик или заказать поставку в кубах, которые перемещаются погрузчиком.', '{"сложно","разгружать","транспорт","водители","оснащены","гидробортами","недостаточно","рекомендуем"}', 'ebfef3d8e26ebfdb', true, NOW()),
  ('obj_048', 'logistics', 'Логистика и Сроки', 'Вы опоздали с доставкой', 'Приношу извинения за задержку. Произошел сбой в логистике. Компенсируем простой скидкой 5% на следующую поставку и предоставим статус груза онлайн.', '{"опоздали","доставкой","приношу","извинения","задержку","произошел","сбой","логистике"}', '284cd8fe54133cf3', true, NOW()),
  ('obj_049', 'logistics', 'Логистика и Сроки', 'Повреждение тары при транспортировке', 'Фотографируйте повреждения до начала приемки. Водитель подпишет акт о браке. Мы заберем испорченный товар и привезем замену в течение 24 часов за наш счет.', '{"повреждение","тары","транспортировке","фотографируйте","повреждения","начала","приемки","водитель"}', '01b3bb949c674454', true, NOW()),
  ('obj_050', 'logistics', 'Логистика и Сроки', 'Отгрузка частями, а нам нужна вся партия сразу', 'Фура загружается консолидировано. Частичная отгрузка приведет к удорожанию логистики для всех участников. Ждем полной готовности склада к приемке.', '{"отгрузка","частями","нужна","партия","сразу","фура","загружается","консолидировано"}', '602212bd85d3e87b', true, NOW()),
  ('obj_051', 'logistics', 'Логистика и Сроки', 'Нет возможности самовывоза', 'Если у вас нет своего транспорта, мы привлекаем надежного перевозчика. Вам нужно только обеспечить подъездные пути и разгрузочную рампу.', '{"возможности","самовывоза","своего","транспорта","привлекаем","надежного","перевозчика","нужно"}', 'ea39f99927c250d9', true, NOW()),
  ('obj_052', 'logistics', 'Логистика и Сроки', 'Бестарное хранение невозможно на нашем объекте', 'Тогда стандартный вариант — бочки или кубы. Рассчитаем оптимальное количество тары исходя из вашего расхода, чтобы минимизировать остаток.', '{"бестарное","хранение","невозможно","нашем","объекте","стандартный","вариант","бочки"}', '013f4a42d7f6f1c2', true, NOW()),
  ('obj_053', 'logistics', 'Логистика и Сроки', 'Нужно переоформление документов на складе', 'Все документы готовятся заранее. Если возникла необходимость в замене, сообщите менеджеру номер счета, он внесет изменения и вышлет новые оригиналы курьером.', '{"нужно","переоформление","документов","складе","документы","готовятся","заранее","возникла"}', '71c1919ab397f1a3', true, NOW()),
  ('obj_054', 'logistics', 'Логистика и Сроки', 'Задержка оформления пропусков для машины', 'Водителю достаточно назвать номер заявки. Если возникают сложности, мой логист свяжется с вашим отделом охраны и решит вопрос по телефону.', '{"задержка","оформления","пропусков","машины","водителю","достаточно","назвать","номер"}', '7c9733028e27c819', true, NOW()),
  ('obj_055', 'logistics', 'Логистика и Сроки', 'Ошибка в адресе доставки', 'Ситуация неприятная. Груз перенаправлен на верный адрес. Из-за крюка доставка задержится на N часов. Просим прощения за доставленные неудобства.', '{"ошибка","адресе","доставки","ситуация","неприятная","груз","перенаправлен","верный"}', '70da5f2de554966e', true, NOW()),
  ('obj_056', 'service', 'Работа с Поставщиком и Сервис', 'Ваш менеджер нам не перезвонил', 'Приношу личные извинения. Он отстранен от работы с вами. Теперь вашим менеджером буду лично я. Все вопросы решаются в режиме реального времени.', '{"менеджер","перезвонил","приношу","личные","извинения","отстранен","работы","вами"}', 'cab7489f41177f3a', true, NOW()),
  ('obj_057', 'service', 'Работа с Поставщиком и Сервис', 'Медленно отвечаете на запросы / письма', 'Стандарты нашей службы поддержки — ответ в течение 30 минут в рабочее время. Видимо, ваше письмо попало в спам. Давайте настроим уведомления, чтобы это не повторялось.', '{"медленно","отвечаете","запросы","письма","стандарты","нашей","службы","поддержки"}', '0ea208c9cb89197f', true, NOW()),
  ('obj_058', 'service', 'Работа с Поставщиком и Сервис', 'Вы не решаете наши проблемы оперативно', 'Проблема требует эскалации. Ставлю задачу руководителю регионального филиала. Контроль решения беру на себя. Жду обратной связи от вас через час.', '{"решаете","наши","проблемы","оперативно","проблема","требует","эскалации","ставлю"}', 'c05f2585a6571a8e', true, NOW()),
  ('obj_059', 'service', 'Работа с Поставщиком и Сервис', 'Нет персонального менеджера', 'С сегодняшнего дня за вами закрепляется личный специалист. Его контакты добавлены в подпись этого письма. Он знает специфику вашего бизнеса.', '{"персонального","менеджера","сегодняшнего","вами","закрепляется","личный","специалист","контакты"}', '4a5b7566a98c8960', true, NOW()),
  ('obj_060', 'service', 'Работа с Поставщиком и Сервис', 'Сложная процедура возврата брака', 'Процедура проста: вызывается представитель поставщика, составляется акт, делается анализ пробы. Если вина подтверждается, мы меняем товар и компенсируем затраты на логистику.', '{"сложная","процедура","возврата","брака","проста","вызывается","представитель","поставщика"}', 'aea52933eda9f4fc', true, NOW()),
  ('obj_061', 'service', 'Работа с Поставщиком и Сервис', 'Невозможно дозвониться до техподдержки', 'Горячая линия работает круглосуточно. Попробуйте позвонить на прямой мобильный номер инженера-технолога [номер телефона].', '{"невозможно","дозвониться","техподдержки","горячая","линия","работает","круглосуточно","попробуйте"}', 'b7def9f0f9fb1276', true, NOW()),
  ('obj_062', 'service', 'Работа с Поставщиком и Сервис', 'Вы постоянно меняете условия договора', 'Условия меняются только в сторону улучшения сервиса для клиента и в соответствии с изменениями законодательства. Текущая редакция договора действует до конца года.', '{"постоянно","меняете","условия","договора","меняются","сторону","улучшения","сервиса"}', '30f37c12d3f8003f', true, NOW()),
  ('obj_063', 'service', 'Работа с Поставщиком и Сервис', 'Менеджер хамит / непрофессионален', 'Такого поведения мы не приемлем. Записываю обращение. Руководитель проведет беседу с сотрудником. Примите мои извинения за инцидент.', '{"менеджер","хамит","непрофессионален","такого","поведения","приемлем","записываю","обращение"}', '83c8be98b15608f8', true, NOW()),
  ('obj_064', 'service', 'Работа с Поставщиком и Сервис', 'Вы забыли приложить документы к поставке', 'Документы переданы водителю. Курьер вернется к вам в течение часа. Либо я перешлю сканы счетов-фактур по электронной почте прямо сейчас.', '{"забыли","приложить","документы","поставке","переданы","водителю","курьер","вернется"}', 'f3dd811f617d6674', true, NOW()),
  ('obj_065', 'service', 'Работа с Поставщиком и Сервис', 'Документы оформлены с ошибками', 'Где именно допущена ошибка? Бухгалтерия уже готовит исправленный комплект. Завтра утром оригиналы будут у вас.', '{"документы","оформлены","ошибками","именно","допущена","ошибка","бухгалтерия","готовит"}', '0351fddfc20ce6d2', true, NOW()),
  ('obj_066', 'service', 'Работа с Поставщиком и Сервис', 'Вы не предоставляете закрывающие бухгалтерские документы вовремя', 'Обычно мы делаем это в течение 3-х рабочих дней после поставки. Сейчас вижу задержку. Отправляю скан УПД немедленно, оригиналы получите курьерской службой сегодня.', '{"предоставляете","закрывающие","бухгалтерские","документы","вовремя","обычно","делаем","течение"}', '10093374fc3c15f1', true, NOW()),
  ('obj_067', 'service', 'Работа с Поставщиком и Сервис', 'Нам нужно официальное письмо о повышении цен', 'Шаблон письма уже готов. Направляю его вам на бланке компании. Подписанный оригинал будет доставлен курьером.', '{"нужно","официальное","письмо","повышении","шаблон","письма","готов","направляю"}', 'b71172f7619e96be', true, NOW()),
  ('obj_068', 'service', 'Работа с Поставщиком и Сервис', 'Вы не идете навстречу в форс-мажорных обстоятельствах', 'Мы всегда открыты к диалогу. Опишите вашу ситуацию. Мы можем рассмотреть перенос сроков оплаты или частичную отгрузку, чтобы поддержать вас.', '{"идете","навстречу","форс-мажорных","обстоятельствах","открыты","диалогу","опишите","вашу"}', '2926ad1ca4038c7d', true, NOW()),
  ('obj_069', 'service', 'Работа с Поставщиком и Сервис', 'Нет прозрачной истории заказов в личном кабинете', 'Ваш доступ к личному кабинету заблокирован из-за смены пароля. Восстанавливаю права доступа. Зайдите в систему через 15 минут.', '{"прозрачной","истории","заказов","личном","кабинете","доступ","личному","кабинету"}', 'b117e1750eb0e3c2', true, NOW()),
  ('obj_070', 'service', 'Работа с Поставщиком и Сервис', 'Сложный процесс согласования спецификаций', 'Чтобы упростить процесс, мы подготовили типовой паспорт продукта. Вам остается только вписать название вашей компании и поставить печать.', '{"сложный","процесс","согласования","спецификаций","упростить","подготовили","типовой","паспорт"}', '06058b8cf8a7fa25', true, NOW()),
  ('obj_071', 'brand', 'Бренд и Лояльность', 'Мы доверяем только мировым гигантам', 'Мировые гиганты тратят огромные бюджеты на маркетинг, что заложено в цену. Мы вкладываем эти деньги в качество сырья. Наши базовые масла поставляются теми же трейдерами, что и для них.', '{"доверяем","мировым","гигантам","мировые","гиганты","тратят","огромные","бюджеты"}', 'a42441424ee89b03', true, NOW()),
  ('obj_072', 'brand', 'Бренд и Лояльность', 'О вас никто не слышал', 'Мы специализируемся на работе с промышленностью, где важны цифры, а не реклама. Вот список наших постоянных клиентов из вашей отрасли: [Список компаний]. Можем организовать визит к ним?', '{"никто","слышал","специализируемся","работе","промышленностью","важны","цифры","реклама"}', '1ddd362e6296eca0', true, NOW()),
  ('obj_073', 'brand', 'Бренд и Лояльность', 'Зачем менять то, что работает? (Мы всегда брали другое)', 'Инновации не стоят на месте. Новые формулы позволяют увеличить ресурс подшипников на 20%. Предлагаю залить наше масло в одну единицу техники для сравнительного теста. Решение будет фактом.', '{"менять","работает","брали","другое","инновации","стоят","месте","новые"}', '2ad5c4465b6eac5e', true, NOW()),
  ('obj_074', 'brand', 'Бренд и Лояльность', 'Ваш бренд новый / неизвестный', 'Бренду на российском рынке 10 лет. Завод построен с нуля по западным технологиям. Мы прошли аудит и получили лицензии от ведущих производителей присадок.', '{"бренд","новый","неизвестный","бренду","российском","рынке","завод","построен"}', '6f087e651cfadb46', true, NOW()),
  ('obj_075', 'brand', 'Бренд и Лояльность', 'Боязнь рисковать с новым поставщиком', 'Минимальный риск — тестовая партия на одной машине. Максимальное обеспечение — банковская гарантия исполнения контракта. Чего еще вам не хватает для спокойствия?', '{"боязнь","рисковать","новым","поставщиком","минимальный","риск","тестовая","партия"}', 'cba05046e7dfe75e', true, NOW()),
  ('obj_076', 'brand', 'Бренд и Лояльность', 'У конкурента имидж лучше', 'Имидж важен для конечного потребителя. Для механика на карьере важна чистая работа гидравлики. Давайте сравним чистоту поршней после 500 моточасов работы.', '{"конкурента","имидж","важен","конечного","потребителя","механика","карьере","важна"}', '4fccdfc58a7a16d6', true, NOW()),
  ('obj_077', 'brand', 'Бренд и Лояльность', 'Нас не устраивает маркетинговая поддержка', 'Какая поддержка вам нужна? POS-материалы для СТО, обучение механиков, участие в промо-акциях? Подготовим план активностей на квартал.', '{"устраивает","маркетинговая","поддержка","нужна","pos-материалы","обучение","механиков","участие"}', '62847924b7efb53e', true, NOW()),
  ('obj_078', 'brand', 'Бренд и Лояльность', 'Вы не участвуете в отраслевых выставках', 'Мы присутствуем на ключевых мероприятиях, таких как [Название выставки]. Следующая встреча там. Запланирую демонстрацию нашего стенда.', '{"участвуете","отраслевых","выставках","присутствуем","ключевых","мероприятиях","таких","название"}', 'd42b36737a7736ce', true, NOW()),
  ('obj_079', 'brand', 'Бренд и Лояльность', 'Негативные отзывы в интернете', 'Отзывы пишут люди. Мы отслеживаем упоминания бренда. Тот конкретный случай, о котором вы говорите, был решен заменой партии. Свяжитесь со мной, я дам контакты довольных клиентов.', '{"негативные","отзывы","интернете","пишут","люди","отслеживаем","упоминания","бренда"}', 'f124447adf36744a', true, NOW()),
  ('obj_080', 'brand', 'Бренд и Лояльность', 'Отсутствие рекламы в профильных СМИ', 'Мы предпочитаем прямую работу с техническими специалистами, а не массовую рекламу. Эффективнее один раз показать продукт в деле, чем сто раз увидеть баннер.', '{"отсутствие","рекламы","профильных","предпочитаем","прямую","работу","техническими","специалистами"}', '51247c0c1cd70a1e', true, NOW()),
  ('obj_081', 'business', 'Специфика бизнеса клиента', 'Наша техника старая, ей нужны другие масла', 'Именно для старой техники у нас есть специальная линейка минеральных масел с усиленным противоизносным пакетом ZDDP. Они разработаны для уплотнений старого образца.', '{"техника","старая","нужны","другие","масла","именно","старой","техники"}', '7cf178161748a2a6', true, NOW()),
  ('obj_082', 'business', 'Специфика бизнеса клиента', 'У нас смешанный парк техники', 'Отлично. У нас есть универсальные продукты (Universal Tractor Oil), которые перекрывают потребности разных классов техники, позволяя вам сократить номенклатуру склада.', '{"смешанный","парк","техники","отлично","универсальные","продукты","universal","tractor"}', '766864b2a294462f', true, NOW()),
  ('obj_083', 'business', 'Специфика бизнеса клиента', 'Мы используем синтетику конкурентов', 'Переход возможен через процедуру промывки системы нашими сервисными составами. Это безопасно и предотвратит свертываемость масел разного типа.', '{"используем","синтетику","конкурентов","переход","возможен","процедуру","промывки","системы"}', '184135e85d8b9c4f', true, NOW()),
  ('obj_084', 'business', 'Специфика бизнеса клиента', 'Работаем в тяжелых условиях (экстремальные температуры, пыль)', 'Для таких задач существует серия Heavy Duty с двойным запасом щелочности и фильтруемостью. Она предотвращает загущение масла от сажи.', '{"работаем","тяжелых","условиях","экстремальные","температуры","пыль","таких","задач"}', '77aa5bced10b4b38', true, NOW()),
  ('obj_085', 'business', 'Специфика бизнеса клиента', 'Техника стоит долго без работы', 'Вам необходимы масла с мощными антикоррозионными присадками. Наш продукт образует прочную пленку на металле, которая держится до 12 месяцев простоя.', '{"техника","стоит","долго","работы","необходимы","масла","мощными","антикоррозионными"}', 'a1acdb221726dfbe', true, NOW()),
  ('obj_086', 'business', 'Специфика бизнеса клиента', 'Специфические требования экологии (биоразлагаемые масла)', 'Есть линейка эко-масел на основе растительных эфиров. Они сертифицированы для работы вблизи водоемов и полностью разлагаются.', '{"специфические","требования","экологии","биоразлагаемые","масла","линейка","эко-масел","основе"}', '84bdaeedbc858e80', true, NOW()),
  ('obj_087', 'business', 'Специфика бизнеса клиента', 'Требования безопасности труда (низкий класс опасности)', 'Предлагаем продукт с пищевым допуском NSF H1. Он безопасен при случайном контакте с продуктами питания.', '{"требования","безопасности","труда","низкий","класс","опасности","предлагаем","продукт"}', 'a3c8ad04f505c012', true, NOW()),
  ('obj_088', 'business', 'Специфика бизнеса клиента', 'Ограничения по хранению ГСМ на территории', 'Можем предложить установку модульной станции очистки масла непосредственно на вашем объекте, что позволит работать по замкнутому циклу.', '{"ограничения","хранению","территории","можем","предложить","установку","модульной","станции"}', '360074697e0a6cfe', true, NOW()),
  ('obj_089', 'business', 'Специфика бизнеса клиента', 'Необходимость утилизации отработанного масла', 'Мы предоставляем эту услугу бесплатно при условии покупки свежего масла у нас. Вывозим', '{"необходимость","утилизации","отработанного","масла","предоставляем","услугу","бесплатно","условии"}', 'ad64c2d871dd2738', true, NOW()),
  ('obj_090', 'business', 'Специфика бизнеса клиента', 'Закупки производятся централизованно головным офисом в другом городе', 'Без проблем. Я свяжусь с вашим куратором в центральном офисе, отправлю ему всю документацию и согласую условия поставки на филиал.', '{"закупки","производятся","централизованно","головным","офисом","другом","городе","проблем"}', '3f0ae4ca8d2779ae', true, NOW()),
  ('obj_091', 'closing', 'Финальные сомнения и отказы', 'Мне нужно подумать', 'Конечно. Что конкретно вызывает вопросы? Цена, сроки или технические параметры? Давайте разберем эти моменты прямо сейчас, чтобы вам было проще принять решение.', '{"нужно","подумать","конкретно","вызывает","вопросы","цена","сроки","технические"}', 'a5793d70207530c4', true, NOW()),
  ('obj_092', 'closing', 'Финальные сомнения и отказы', 'Пришлите коммерческое предложение, мы сравним', 'КП подготовлю. Но чтобы сравнение было корректным, уточните: какой класс вязкости, объем первой партии и желаемый график поставок? Так КП будет точным.', '{"пришлите","коммерческое","предложение","сравним","подготовлю","сравнение","корректным","уточните"}', '15c522c129cc3b51', true, NOW()),
  ('obj_093', 'closing', 'Финальные сомнения и отказы', 'Зимой замерзнет / летом потечет', 'Наша продукция проходит испытания в климатической камере при температурах от -40°C до +50°C. Вязкостно-температурная кривая полностью соответствует вашему региону эксплуатации.', '{"зимой","замерзнет","летом","потечет","продукция","проходит","испытания","климатической"}', 'f2f561858f877e25', true, NOW()),
  ('obj_094', 'closing', 'Финальные сомнения и отказы', 'Нет нужного документа (MSDS, TDS, Паспорт качества)', 'Отправляю запрос производителю. Документ появится в базе в течение часа. Подтвердите почту, куда его направить?', '{"нужного","документа","msds","tds","паспорт","качества","отправляю","запрос"}', 'dceaaefd287dd4c7', true, NOW()),
  ('obj_095', 'closing', 'Финальные сомнения и отказы', 'Просто оставьте каталог', 'Каталог оставлю. Но позвольте задать пару вопросов о ваших задачах. Часто клиенты находят в нем решения проблем, о которых они даже не подозревали.', '{"просто","оставьте","каталог","оставлю","позвольте","задать","пару","вопросов"}', '52683bf4be820902', true, NOW()),
  ('obj_096', 'closing', 'Финальные сомнения и отказы', 'Сейчас не сезон / затишье в бизнесе', 'Именно в низкий сезон выгодно закупать ГСМ, так как цены стабильны, а логистика свободна. Заложив базу сейчас, вы обеспечите бесперебойную работу в пик нагрузки.', '{"сезон","затишье","бизнесе","именно","низкий","выгодно","закупать","цены"}', 'dadd96625922c781', true, NOW()),
  ('obj_097', 'closing', 'Финальные сомнения и отказы', 'Это решение принимает генеральный директор, я не уполномочен', 'Понимаю. Я подготовлю краткую справку для руководителя: три причины, почему стоит выбрать нас, и расчет экономической выгоды. Поможет обосновать покупку.', '{"решение","принимает","генеральный","директор","уполномочен","понимаю","подготовлю","краткую"}', '79be84811bf80da5', true, NOW()),
  ('obj_098', 'closing', 'Финальные сомнения и отказы', 'Мы уже нашли поставщика на этот год', 'Хорошо иметь надежный тыл. Предлагаю стать вторым номером в списке. Если у основного партнера случится сбой, вы знаете, кому позвонить, чтобы спасти производство.', '{"нашли","поставщика","иметь","надежный","предлагаю","стать","вторым","номером"}', 'c5c5962493daa32e', true, NOW()),
  ('obj_099', 'closing', 'Финальные сомнения и отказы', 'Спасибо, мы вам сами позвоним', 'Буду ждать звонка. Сохраняю за вами специальные условия на 7 дней. Если ситуация изменится, просто скажите', '{"спасибо","сами","позвоним","буду","ждать","звонка","сохраняю","вами"}', '04577fdbcb2746ba', true, NOW()),
  ('obj_100', 'closing', 'Финальные сомнения и отказы', 'Нам ничего не нужно', 'Принято. Желаю успехов в делах. Надеюсь, когда возникнет потребность в качественном сервисе, вы вспомните о нашем разговоре.', '{"нужно","принято","желаю","успехов","делах","надеюсь","возникнет","потребность"}', 'd9bb74540fe02160', true, NOW());
